    26	/// <summary>
    27	/// A concrete implementation of DailyTimeIntervalTrigger that is used to fire a <see cref="IJobDetail"/>
    28	/// based upon daily repeating time intervals.
    29	/// </summary>
    30	/// <remarks>
    31	/// <para>
    32	/// The trigger will fire every N (<see cref="IDailyTimeIntervalTrigger.RepeatInterval"/> ) seconds, minutes or hours
    33	/// (see <see cref="IDailyTimeIntervalTrigger.RepeatInterval"/>) during a given time window on specified days of the week.
    34	/// </para>
    35	/// <para>
    36	/// For example#1, a trigger can be set to fire every 72 minutes between 8:00 and 11:00 everyday. It's fire times would
    37	/// be 8:00, 9:12, 10:24, then next day would repeat: 8:00, 9:12, 10:24 again.
    38	/// </para>
    39	/// <para>
    40	/// For example#2, a trigger can be set to fire every 23 minutes between 9:20 and 16:47 Monday through Friday.
    41	/// </para>
    42	/// <para>
    43	/// On each day, the starting fire time is reset to startTimeOfDay value, and then it will add repeatInterval value to it until
    44	/// the endTimeOfDay is reached. If you set daysOfWeek values, then fire time will only occur during those week days period. Again,
    45	/// remember this trigger will reset fire time each day with startTimeOfDay, regardless of your interval or endTimeOfDay!
    46	/// </para>
    47	/// <para>
    48	/// The default values for fields if not set are: startTimeOfDay defaults to 00:00:00, the endTimeOfDay default to 23:59:59,
    49	/// and daysOfWeek is default to every day. The startTime default to current time-stamp now, while endTime has not value.
    50	/// </para>
    51	/// <para>
    52	/// If startTime is before startTimeOfDay, then startTimeOfDay will be used and startTime has no affect other than to specify
    53	/// the first day of firing. Else if startTime is  after startTimeOfDay, then the first fire time for that day will be the next
    54	/// interval after the startTime. For example, if you set startingTimeOfDay=9am, endingTimeOfDay=11am, interval=15 mins, and startTime=9:33am,
    55	/// then the next fire time will be 9:45pm. Note also that if you do not set startTime value, the trigger builder will default to current time, and current time
    56	/// maybe before or after the startTimeOfDay! So be aware how you set your startTime.
    57	/// </para>
    58	/// <para>
    59	/// This trigger also supports a "repeatCount" feature to limit the number of times the trigger
    60	/// fires per day. Setting repeatCount=0 means the trigger will fire once per day at startTimeOfDay.
    61	/// Setting repeatCount=N means the trigger will fire N+1 times per day (the initial fire plus N
    62	/// repeats), then advance to the next valid day and repeat. Unlike SimpleTrigger which uses
    63	/// repeatCount as a global total, DailyTimeIntervalTrigger applies repeatCount per day. The
    64	/// default value of repeatCount is set to REPEAT_INDEFINITELY.
    65	/// </para>
    66	/// </remarks>
    67	/// <see cref="IDailyTimeIntervalTrigger"/>
    68	/// <see cref="DailyTimeIntervalScheduleBuilder"/>
    69	/// <since>2.0</since>
    70	/// <author>James House</author>
    71	/// <author>Zemian Deng saltnlight5@gmail.com</author>
    72	/// <author>Nuno Maia (.NET)</author>
    73	[Serializable]
    74	#pragma warning disable CA1708
    75	public sealed class DailyTimeIntervalTriggerImpl : AbstractTrigger, IDailyTimeIntervalTrigger
    76	#pragma warning restore CA1708
    77	{
    78	    /// <summary>
    79	    /// Used to indicate the 'repeat count' of the trigger is indefinite. Or in
    80	    /// other words, the trigger should repeat continually until the trigger's
    81	    /// ending timestamp.
    82	    /// </summary>
    83	    public const int RepeatIndefinitely = -1;
    84	    private DateTimeOffset startTimeUtc;
    85	    private DateTimeOffset? endTimeUtc;
    86	    private DateTimeOffset? nextFireTimeUtc;
    87	    private DateTimeOffset? previousFireTimeUtc;
    88	    private int repeatInterval = 1;
    89	    private IntervalUnit repeatIntervalUnit = IntervalUnit.Minute;
    90	    private HashSet<DayOfWeek> daysOfWeek = null!;
    91	    private TimeOfDay startTimeOfDay = null!;
    92	    private TimeOfDay endTimeOfDay = null!;
    93	    private bool complete;
    94	    private int repeatCount = RepeatIndefinitely;
    95	    internal TimeZoneInfo? timeZone;
    96	
    97	    // Serializing TimeZones is tricky in .NET Core. This helper will ensure that we get the same timezone on a given platform,
    98	    // but there's not yet a good method of serializing/deserializing timezones cross-platform since Windows timezone IDs don't
    99	    // match IANA tz IDs (https://en.wikipedia.org/wiki/List_of_tz_database_time_zones). This feature is coming, but depending
   100	    // on timelines, it may be worth doign the mapping here.
   101	    // More info: https://github.com/dotnet/corefx/issues/7757
   102	    private string? timeZoneInfoId
   103	    {
   104	        get => timeZone?.Id;
   105	        set => timeZone = value is null ? null : TimeZoneInfo.FindSystemTimeZoneById(value);
   106	    }
   107	
   108	    /// <summary>
   109	    /// Create a  <see cref="IDailyTimeIntervalTrigger"/> with no settings.
   110	    /// </summary>
   111	    /// <param name="timeProvider">Time provider instance to use, defaults to <see cref="TimeProvider.System"/></param>
   112	    public DailyTimeIntervalTriggerImpl(TimeProvider? timeProvider = null) : base(timeProvider ?? TimeProvider.System)
   113	    {
   114	    }
   115	
   116	    /// <summary>
   117	    /// Create a <see cref="IDailyTimeIntervalTrigger" /> that will occur immediately, and
   118	    /// repeat at the given interval.
   119	    /// </summary>
   120	    /// <param name="name"></param>
   121	    /// <param name="startTimeOfDayUtc">The <see cref="TimeOfDay" /> that the repeating should begin occurring.</param>
   122	    /// <param name="endTimeOfDayUtc">The <see cref="TimeOfDay" /> that the repeating should stop occurring.</param>
   123	    /// <param name="intervalUnit">The repeat interval unit. The only intervals that are valid for this type of trigger are <see cref="IntervalUnit.Second"/>, <see cref="IntervalUnit.Minute"/>, and <see cref="IntervalUnit.Hour"/>.</param>
   124	    /// <param name="repeatInterval"></param>
   125	    /// <param name="timeProvider">Time provider instance to use, defaults to <see cref="TimeProvider.System"/></param>
   126	    /// <exception cref="ArgumentNullException"><paramref name="name"/> is <see langword="null"/>.</exception>
   127	    public DailyTimeIntervalTriggerImpl(
   128	        string name,
   129	        TimeOfDay startTimeOfDayUtc,
   130	        TimeOfDay endTimeOfDayUtc,
   131	        IntervalUnit intervalUnit,
   132	        int repeatInterval,
   133	        TimeProvider? timeProvider = null)
   134	        : this(name, SchedulerConstants.DefaultGroup, startTimeOfDayUtc, endTimeOfDayUtc, intervalUnit, repeatInterval, timeProvider)
   135	    {
   136	    }
   137	
   138	    /// <summary>
   139	    /// Create a <see cref="IDailyTimeIntervalTrigger" /> that will occur immediately, and
   140	    /// repeat at the given interval.
   141	    /// </summary>
   142	    /// <param name="name"></param>
   143	    /// <param name="group"></param>
   144	    /// <param name="startTimeOfDayUtc">The <see cref="TimeOfDay" /> that the repeating should begin occurring.</param>
   145	    /// <param name="endTimeOfDayUtc">The <see cref="TimeOfDay" /> that the repeating should stop occurring.</param>
   146	    /// <param name="intervalUnit">The repeat interval unit. The only intervals that are valid for this type of trigger are <see cref="IntervalUnit.Second"/>, <see cref="IntervalUnit.Minute"/>, and <see cref="IntervalUnit.Hour"/>.</param>
   147	    /// <param name="repeatInterval"></param>
   148	    /// <param name="timeProvider"><response clipped><NOTE>Due to the max output limit, only part of this file has been shown to you. You should retry this tool after you have searched inside the file with `grep -n` in order to find the line numbers of what you are looking for.</NOTE> = new HashSet<DayOfWeek>(DaysOfWeek);
   149	        if (forceToAdvanceNextDay || !daysOfWeek.Contains(dayOfWeekOfFireTime))
   150	        {
   151	            // Advance one day at a time until next available date.
   152	            for (int i = 1; i <= 7; i++)
   153	            {
   154	                fireTimeStartDateCal = fireTimeStartDateCal.AddDays(1);
   155	                dayOfWeekOfFireTime = fireTimeStartDateCal.DayOfWeek;
   156	                if (daysOfWeek.Contains(dayOfWeekOfFireTime))
   157	                {
   158	                    fireTime = fireTimeStartDateCal;
   159	                    // apply timezone for this date & time
   160	                    fireTime = new DateTimeOffset(fireTime.DateTime, TimeZoneUtil.GetUtcOffset(fireTime, TimeZone));
   161	                    break;
   162	                }
   163	            }
   164	        }
   165	
   166	        // Check fireTime not pass the endTime
   167	        DateTimeOffset? endTime = EndTimeUtc;
   168	
   169	        if (endTime is not null && fireTime > endTime.Value)
   170	        {
   171	            return null;
   172	        }
   173	
   174	        return fireTime;
   175	    }
   176	
   177	    /// <summary>
   178	    /// Returns the final time at which the <see cref="IDailyTimeIntervalTrigger" /> will
   179	    /// fire, if there is no end time set, null will be returned.
   180	    /// </summary>
   181	    /// <remarks>Note that the return time may be in the past.</remarks>
   182	    /// <returns></returns>
   183	    public override DateTimeOffset? FinalFireTimeUtc
   184	    {
   185	        get
   186	        {
   187	            if (complete || EndTimeUtc is null)
   188	            {
   189	                return null;
   190	            }
   191	
   192	            // We have an endTime, we still need to check to see if there is a endTimeOfDay if that's applicable.
   193	            DateTimeOffset? endTime = EndTimeUtc;
   194	            DateTimeOffset? endTimeOfDayDate = endTimeOfDay?.GetTimeOfDayForDate(endTime);
   195	            if (endTime < endTimeOfDayDate)
   196	            {
   197	                endTime = endTimeOfDayDate;
   198	            }
   199	            return endTime;
   200	        }
   201	    }
   202	
   203	    /// <summary>
   204	    /// Determines whether or not the <see cref="IDailyTimeIntervalTrigger" /> will occur
   205	    /// again.
   206	    /// </summary>
   207	    /// <returns></returns>
   208	    public override bool GetMayFireAgain()
   209	    {
   210	        return GetNextFireTimeUtc() is not null;
   211	    }
   212	
   213	    /// <summary>
   214	    /// Validates whether the properties of the <see cref="IJobDetail" /> are
   215	    /// valid for submission into a <see cref="IScheduler" />.
   216	    /// </summary>
   217	    public override void Validate()
   218	    {
   219	        base.Validate();
   220	
   221	        if (repeatIntervalUnit != IntervalUnit.Second && repeatIntervalUnit != IntervalUnit.Minute && repeatIntervalUnit != IntervalUnit.Hour)
   222	        {
   223	            Throw.SchedulerException("Invalid repeat IntervalUnit (must be Second, Minute or Hour).");
   224	        }
   225	        if (repeatInterval < 1)
   226	        {
   227	            Throw.SchedulerException("Repeat Interval cannot be zero.");
   228	        }
   229	
   230	        // Ensure interval does not exceed 24 hours
   231	        const long SecondsInHour = 24 * 60 * 60L;
   232	        if (repeatIntervalUnit == IntervalUnit.Second && repeatInterval > SecondsInHour)
   233	        {
   234	            Throw.SchedulerException("repeatInterval can not exceed 24 hours (" + SecondsInHour + " seconds). Given " + repeatInterval);
   235	        }
   236	        if (repeatIntervalUnit == IntervalUnit.Minute && repeatInterval > SecondsInHour / 60L)
   237	        {
   238	            Throw.SchedulerException("repeatInterval can not exceed 24 hours (" + SecondsInHour / 60L + " minutes). Given " + repeatInterval);
   239	        }
   240	        if (repeatIntervalUnit == IntervalUnit.Hour && repeatInterval > 24)
   241	        {
   242	            Throw.SchedulerException("repeatInterval can not exceed 24 hours. Given " + repeatInterval + " hours.");
   243	        }
   244	
   245	        // Ensure timeOfDay is in order.
   246	        // NOTE: We allow startTimeOfDay to be set equal to endTimeOfDay so the repeatCount can be set to 1.
   247	        if (EndTimeOfDay is not null
   248	            && !StartTimeOfDay.Equals(EndTimeOfDay)
   249	            && !StartTimeOfDay.Before(EndTimeOfDay))
   250	        {
   251	            Throw.SchedulerException($"StartTimeOfDay {startTimeOfDay} should not come after endTimeOfDay {endTimeOfDay}");
   252	        }
   253	    }
   254	
   255	    /// <summary>
   256	    /// The days of the week upon which to fire.
   257	    /// </summary>
   258	    /// <returns>
   259	    /// A Set containing the integers representing the days of the week, per the values 0-6 as defined by
   260	    /// DayOfWees.Sunday - DayOfWeek.Saturday.
   261	    /// </returns>
   262	    public IReadOnlyCollection<DayOfWeek> DaysOfWeek
   263	    {
   264	        get
   265	        {
   266	            if (daysOfWeek is null)
   267	            {
   268	                daysOfWeek = new HashSet<DayOfWeek>(DailyTimeIntervalScheduleBuilder.AllDaysOfTheWeek);
   269	            }
   270	            return daysOfWeek;
   271	        }
   272	
   273	        set
   274	        {
   275	            if (value is null || value.Count == 0)
   276	            {
   277	                Throw.ArgumentException("DaysOfWeek set must be a set that contains at least one day.");
   278	            }
   279	            if (value.Count == 0)
   280	            {
   281	                Throw.ArgumentException("DaysOfWeek set must contain at least one day.");
   282	            }
   283	
   284	            daysOfWeek = new HashSet<DayOfWeek>(value);
   285	        }
   286	    }
   287	
   288	    /// <summary>
   289	    /// The time of day to start firing at the given interval.
   290	    /// </summary>
   291	    public TimeOfDay StartTimeOfDay
   292	    {
   293	        get
   294	        {
   295	            if (startTimeOfDay is null)
   296	            {
   297	                startTimeOfDay = new TimeOfDay(0, 0, 0);
   298	            }
   299	            return startTimeOfDay;
   300	        }
   301	        set
   302	        {
   303	            if (value is null)
   304	            {
   305	                Throw.ArgumentException("Start time of day cannot be null");
   306	            }
   307	
   308	            TimeOfDay eTime = EndTimeOfDay;
   309	            if (eTime is not null && eTime.Before(value))
   310	            {
   311	                Throw.ArgumentException("End time of day cannot be before start time of day");
   312	            }
   313	
   314	            startTimeOfDay = value;
   315	        }
   316	    }
   317	
   318	    /// <summary>
   319	    /// The time of day to complete firing at the given interval.
   320	    /// </summary>
   321	    public TimeOfDay EndTimeOfDay
   322	    {
   323	        get => endTimeOfDay;
   324	        set
   325	        {
   326	            if (value is null)
   327	            {
   328	                Throw.ArgumentException("End time of day cannot be null");
   329	            }
   330	
   331	            TimeOfDay sTime = StartTimeOfDay;
   332	            if (sTime is not null && value.Before(sTime))
   333	            {
   334	                Throw.ArgumentException("End time of day cannot be before start time of day");
   335	            }
   336	            endTimeOfDay = value;
   337	        }
   338	    }
   339	
   340	    /// <summary>
   341	    /// Get a <see cref="IScheduleBuilder" /> that is configured to produce a
   342	    /// schedule identical to this trigger's schedule.
   343	    /// </summary>
   344	    /// <returns></returns>
   345	    /// <see cref="TriggerBuilder"/>
   346	    public override IScheduleBuilder GetScheduleBuilder()
   347	    {
   348	        DailyTimeIntervalScheduleBuilder cb = DailyTimeIntervalScheduleBuilder.Create()
   349	            .WithInterval(RepeatInterval, RepeatIntervalUnit)
   350	            .OnDaysOfTheWeek(DaysOfWeek)
   351	            .StartingDailyAt(StartTimeOfDay)
   352	            .EndingDailyAt(EndTimeOfDay)
   353	            .WithRepeatCount(RepeatCount)
   354	            .InTimeZone(TimeZone);
   355	
   356	        switch (MisfireInstruction)
   357	        {
   358	            case Quartz.MisfireInstruction.DailyTimeIntervalTrigger.DoNothing:
   359	                cb.WithMisfireHandlingInstructionDoNothing();
   360	                break;
   361	            case Quartz.MisfireInstruction.DailyTimeIntervalTrigger.FireOnceNow:
