using Quartz;
using Quartz.Spi;

var tz = TimeZoneInfo.FindSystemTimeZoneById("W. Europe Standard Time");

DateTime startDateTime = new DateTime(2020, 10, 25);
DateTimeOffset startDateTimeOffset = new DateTimeOffset(startDateTime, tz.GetUtcOffset(startDateTime));
int daysAhead = 3;

TriggerBuilder triggerBuilder = TriggerBuilder.Create()
    .WithIdentity("id")
    .ForJob("job")
    .StartAt(new DateTimeOffset(startDateTime.AddMinutes(1).AddSeconds(5), tz.GetUtcOffset(startDateTime.AddMinutes(1).AddSeconds(5))))
    .WithDailyTimeIntervalSchedule(
        scheduleBuilder =>
        {
            scheduleBuilder.OnEveryDay().WithIntervalInHours(24);
            scheduleBuilder
                .StartingDailyAt(new TimeOfDay(0, 1, 5))
                .EndingDailyAt(new TimeOfDay(23, 59, 59))
                .WithMisfireHandlingInstructionDoNothing();
        });

IOperableTrigger operableTrigger = (IOperableTrigger)triggerBuilder.Build();
if (operableTrigger is Quartz.Impl.Triggers.DailyTimeIntervalTriggerImpl dailyTrigger)
{
    dailyTrigger.TimeZone = tz;
}

IReadOnlyList<DateTimeOffset> fireTimes =
    TriggerUtils.ComputeFireTimesBetween(
        operableTrigger,
        null,
        startDateTimeOffset,
        startDateTimeOffset.AddDays(daysAhead));

Console.WriteLine($"Fire times count: {fireTimes.Count}");
foreach (var ft in fireTimes)
{
    Console.WriteLine($"  UTC: {ft.ToUniversalTime():yyyy-MM-dd HH:mm:ss zzz}, Local: {ft.LocalDateTime:yyyy-MM-dd HH:mm:ss zzz}");
}

Console.WriteLine();
Console.WriteLine($"Expected: 3 fire times (Oct 25, 26, 27 at 00:01:05 local)");
Console.WriteLine($"Actual:   {fireTimes.Count} fire times");

var expected1 = new DateTimeOffset(new DateTime(2020, 10, 25, 0, 1, 5), tz.GetUtcOffset(new DateTime(2020, 10, 25, 0, 1, 5)));
var expected2 = new DateTimeOffset(new DateTime(2020, 10, 26, 0, 1, 5), tz.GetUtcOffset(new DateTime(2020, 10, 26, 0, 1, 5)));
var expected3 = new DateTimeOffset(new DateTime(2020, 10, 27, 0, 1, 5), tz.GetUtcOffset(new DateTime(2020, 10, 27, 0, 1, 5)));

bool pass = fireTimes.Count == 3
    && fireTimes[0].LocalDateTime == expected1
    && fireTimes[1].LocalDateTime == expected2
    && fireTimes[2].LocalDateTime == expected3;

Console.WriteLine(pass ? "PASS" : "FAIL - Bug reproduced!");
return pass ? 0 : 1;

